import { useMemo, useState } from "react";
import { useDropzone } from "react-dropzone";
import toast from "react-hot-toast";
import api from "../../api/client";
import { parseCsvText, exportRowsAsCsv } from "../../utils/csv";
import { useAppStore } from "../../store/appStore";

export default function BulkUploadTab() {
  const { subscription, fetchSubscription, online } = useAppStore();
  const [emails, setEmails] = useState([]);
  const [enableSMTP, setEnableSMTP] = useState(false);
  const [progress, setProgress] = useState(0);
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);

  const onDrop = async (acceptedFiles) => {
    const file = acceptedFiles[0];
    if (!file) return;
    const text = await file.text();
    const parsed = parseCsvText(text);
    setEmails(parsed);
    setResults([]);
    setProgress(0);
  };

  const { getRootProps, getInputProps, open } = useDropzone({
    onDrop,
    noClick: true,
    multiple: false,
    accept: {
      "text/csv": [".csv"],
      "application/vnd.ms-excel": [".csv"],
    },
  });

  const estimatedCost = useMemo(() => emails.length * (enableSMTP ? 1 : 0.5), [emails.length, enableSMTP]);
  const insufficient = (subscription?.currentCredits || 0) < estimatedCost;

  const runBulk = async () => {
    if (!online) {
      toast.error("Bulk validation needs internet connection");
      return;
    }
    setLoading(true);
    try {
      setProgress(25);
      const response = await api.post("/validate/bulk", { emails, enableSMTP });
      setProgress(100);
      setResults(response.data.results || []);
      await fetchSubscription();
      toast.success("Bulk validation complete");
    } catch (err) {
      toast.error(err?.response?.data?.message || "Bulk validation failed");
    } finally {
      setLoading(false);
      setTimeout(() => setProgress(0), 600);
    }
  };

  return (
    <div className="card space-y-4">
      <h3 className="text-lg font-semibold">Bulk Upload</h3>
      <div {...getRootProps()} className="rounded-lg border-2 border-dashed border-slate-300 bg-slate-50 p-6 text-center">
        <input {...getInputProps()} />
        <p className="text-sm text-slate-600">Drag and drop CSV file here</p>
        <button className="btn-outline mt-3" onClick={open}>Browse Files</button>
      </div>

      <label className="flex items-center gap-2 text-sm">
        <input type="checkbox" checked={enableSMTP} onChange={(e) => setEnableSMTP(e.target.checked)} />
        Enable server verification
      </label>

      <p className="text-sm">Rows loaded: <strong>{emails.length}</strong></p>
      <p className="text-sm">Estimated credit cost: <strong>{estimatedCost}</strong></p>
      {insufficient && <p className="text-sm text-red-600">Not enough credits for this batch.</p>}

      {progress > 0 && <div className="h-2 overflow-hidden rounded bg-slate-200"><div className="h-full bg-brand-500" style={{ width: `${progress}%` }} /></div>}

      <div className="flex gap-2">
        <button className="btn-primary" disabled={!emails.length || loading || insufficient} onClick={runBulk}>{loading ? "Processing..." : "Validate All"}</button>
        <button className="btn-outline" disabled={!results.length} onClick={() => exportRowsAsCsv("bulk-results.csv", results)}>Export Results as CSV</button>
      </div>

      {!!results.length && (
        <div className="max-h-72 overflow-auto rounded border border-slate-200">
          <table className="min-w-full text-sm">
            <thead className="bg-slate-100">
              <tr>
                <th className="px-3 py-2 text-left">Email</th>
                <th className="px-3 py-2 text-left">Status</th>
                <th className="px-3 py-2 text-left">Reason</th>
                <th className="px-3 py-2 text-left">Cost</th>
              </tr>
            </thead>
            <tbody>
              {results.map((row, idx) => (
                <tr key={`${row.email}-${idx}`} className="border-t border-slate-200">
                  <td className="px-3 py-2">{row.email}</td>
                  <td className="px-3 py-2">{row.isValid ? "Valid" : "Invalid"}</td>
                  <td className="px-3 py-2">{row.reason}</td>
                  <td className="px-3 py-2">{row.creditCost}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
